import{supabase}from './supabase-client.js';import{auth}from './auth-service.js';export const leads={async getAll(filters={}){let query=supabase.from('leads').select('*');if(filters.status)query=query.eq('status',filters.status);if(filters.source)query=query.eq('source',filters.source);if(filters.temperature)query=query.eq('temperature',filters.temperature);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('leads').select('*').eq('id',id).single();return{data,error};},async create(lead){const{data,error}=await supabase .from('leads').insert(lead).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('leads').update(updates).eq('id',id).select().single();return{data,error};},async delete(id){const{error}=await supabase .from('leads').delete().eq('id',id);return{error};},async getStats(){const{data,error}=await supabase .from('leads').select('status,temperature');if(error)return{data: null,error};const stats={total: data.length,new: data.filter(l=>l.status==='new').length,contacted: data.filter(l=>l.status==='contacted').length,qualified: data.filter(l=>l.status==='qualified').length,won: data.filter(l=>l.status==='won').length,hot: data.filter(l=>l.temperature==='hot').length,warm: data.filter(l=>l.temperature==='warm').length,cold: data.filter(l=>l.temperature==='cold').length};return{data: stats,error: null};}};export const clients={async getAll(){const{data,error}=await supabase .from('clients').select('*,user:users(*)').order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('clients').select('*,user:users(*),projects(*)').eq('id',id).single();return{data,error};},async create(client){const{data,error}=await supabase .from('clients').insert(client).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('clients').update(updates).eq('id',id).select().single();return{data,error};}};export const projects={async getAll(clientId=null){let query=supabase .from('projects').select('*,client:clients(*)');if(clientId)query=query.eq('client_id',clientId);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('projects').select('*,client:clients(*),campaigns(*)').eq('id',id).single();return{data,error};},async create(project){const{data,error}=await supabase .from('projects').insert(project).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('projects').update(updates).eq('id',id).select().single();return{data,error};},async updateProgress(id,progress){return this.update(id,{progress});}};export const campaigns={async getAll(filters={}){let query=supabase .from('campaigns').select('*,client:clients(*),project:projects(*)');if(filters.status)query=query.eq('status',filters.status);if(filters.platform)query=query.eq('platform',filters.platform);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('campaigns').select('*,client:clients(*),project:projects(*)').eq('id',id).single();return{data,error};},async create(campaign){const{data,error}=await supabase .from('campaigns').insert(campaign).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('campaigns').update(updates).eq('id',id).select().single();return{data,error};},async updateMetrics(id,metrics){const{data: current}=await this.getById(id);const newMetrics={...current.metrics,...metrics};return this.update(id,{metrics: newMetrics});},async getStats(){const{data,error}=await supabase .from('campaigns').select('status,budget,spent,metrics');if(error)return{data: null,error};const active=data.filter(c=>c.status==='active');const totalBudget=data.reduce((sum,c)=>sum+(c.budget||0),0);const totalSpent=data.reduce((sum,c)=>sum+(c.spent||0),0);const totalLeads=data.reduce((sum,c)=>sum+(c.metrics?.leads||0),0);const avgRoi=active.length>0 ? active.reduce((sum,c)=>sum+(c.metrics?.roi||0),0)/active.length : 0;return{data:{total: data.length,active: active.length,totalBudget,totalSpent,totalLeads,avgRoi: avgRoi.toFixed(1)},error: null};}};export const invoices={async getAll(clientId=null){let query=supabase .from('invoices').select('*,client:clients(*),project:projects(*)');if(clientId)query=query.eq('client_id',clientId);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('invoices').select('*,client:clients(*),project:projects(*)').eq('id',id).single();return{data,error};},async create(invoice){invoice.total=(invoice.amount||0)+(invoice.tax||0);const{data,error}=await supabase .from('invoices').insert(invoice).select().single();return{data,error};},async update(id,updates){if(updates.amount||updates.tax){updates.total=(updates.amount||0)+(updates.tax||0);}const{data,error}=await supabase .from('invoices').update(updates).eq('id',id).select().single();return{data,error};},async markAsPaid(id){return this.update(id,{status: 'paid',paid_at: new Date().toISOString()});},async getStats(clientId=null){let query=supabase.from('invoices').select('amount,total,status');if(clientId)query=query.eq('client_id',clientId);const{data,error}=await query;if(error)return{data: null,error};const stats={total: data.reduce((sum,i)=>sum+(i.total||0),0),paid: data.filter(i=>i.status==='paid').reduce((sum,i)=>sum+(i.total||0),0),pending: data.filter(i=>i.status==='sent'||i.status==='overdue').reduce((sum,i)=>sum+(i.total||0),0),overdue: data.filter(i=>i.status==='overdue').length};return{data: stats,error: null};}};export const deals={async getAll(filters={}){let query=supabase .from('deals').select('*,lead:leads(*),client:clients(*),assigned:users(*)');if(filters.stage)query=query.eq('stage',filters.stage);if(filters.assigned_to)query=query.eq('assigned_to',filters.assigned_to);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('deals').select('*,lead:leads(*),client:clients(*),assigned:users(*)').eq('id',id).single();return{data,error};},async create(deal){const{data,error}=await supabase .from('deals').insert(deal).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('deals').update(updates).eq('id',id).select().single();return{data,error};},async updateStage(id,stage){const updates={stage};if(stage==='won'){updates.won_at=new Date().toISOString();updates.probability=100;}return this.update(id,updates);},async getPipelineStats(){const{data,error}=await supabase .from('deals').select('stage,value,probability');if(error)return{data: null,error};const stages=['discovery','proposal','negotiation','won','lost'];const stats=stages.map(stage=>({stage,count: data.filter(d=>d.stage===stage).length,value: data.filter(d=>d.stage===stage).reduce((sum,d)=>sum+(d.value||0),0),weighted: data.filter(d=>d.stage===stage).reduce((sum,d)=>sum+(d.value||0)*(d.probability||0)/100,0)}));return{data: stats,error: null};}};export const content={async getAll(filters={}){let query=supabase .from('content_calendar').select('*,creator:users(*)');if(filters.status)query=query.eq('status',filters.status);if(filters.platform)query=query.eq('platform',filters.platform);const{data,error}=await query.order('scheduled_at',{ascending: true});return{data,error};},async create(post){const{data,error}=await supabase .from('content_calendar').insert(post).select().single();return{data,error};},async update(id,updates){const{data,error}=await supabase .from('content_calendar').update(updates).eq('id',id).select().single();return{data,error};},async publish(id){return this.update(id,{status: 'published',published_at: new Date().toISOString()});}};export const budget={async getAll(period=null){let query=supabase.from('budget_tracking').select('*');if(period)query=query.eq('period',period);const{data,error}=await query.order('category');return{data,error};},async upsert(category,period,allocated){const{data,error}=await supabase .from('budget_tracking').upsert({category,period,allocated},{onConflict: 'category,period'}).select().single();return{data,error};},async addSpending(category,period,amount){const{data: current}=await supabase .from('budget_tracking').select('spent').eq('category',category).eq('period',period).single();const newSpent=(current?.spent||0)+amount;const{data,error}=await supabase .from('budget_tracking').update({spent: newSpent}).eq('category',category).eq('period',period).select().single();return{data,error};}};export const activities={async getRecent(limit=10){const{data,error}=await supabase .from('activities').select('*,user:users(full_name,avatar_url)').order('created_at',{ascending: false}).limit(limit);return{data,error};},async log(entityType,entityId,action,description='',metadata={}){const user=await auth.getUser();const{data,error}=await supabase .from('activities').insert({user_id: user?.id,entity_type: entityType,entity_id: entityId,action,description,metadata}).select().single();return{data,error};}};export const strategic={async getCompetitors(){const{data,error}=await supabase .from('competitors').select('*').order('name');return{data,error};},async addCompetitor(competitor){const{data,error}=await supabase .from('competitors').insert(competitor).select().single();return{data,error};},async getNotes(category=null){let query=supabase.from('strategic_notes').select('*');if(category)query=query.eq('category',category);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};},async addNote(note){const{data,error}=await supabase .from('strategic_notes').insert(note).select().single();return{data,error};}};export const seo={async getKeywords(){const{data,error}=await supabase .from('seo_keywords').select('*').order('search_volume',{ascending: false});return{data,error};},async addKeyword(keyword){const{data,error}=await supabase .from('seo_keywords').insert(keyword).select().single();return{data,error};},async updateRank(id,currentRank){const{data,error}=await supabase .from('seo_keywords').update({current_rank: currentRank,last_checked_at: new Date().toISOString()}).eq('id',id).select().single();return{data,error};}};export const workflows={async getAll(){const{data,error}=await supabase .from('workflows').select('*').order('name');return{data,error};},async create(workflow){const{data,error}=await supabase .from('workflows').insert(workflow).select().single();return{data,error};},async toggle(id,isActive){const{data,error}=await supabase .from('workflows').update({is_active: isActive}).eq('id',id).select().single();return{data,error};},async run(id){const{data,error}=await supabase .from('workflows').update({last_run_at: new Date().toISOString()}).eq('id',id).select().single();return{data,error};}};export const agents={async getAll(){const{data,error}=await supabase .from('agents').select('*').order('name');return{data,error};},async getById(id){const{data,error}=await supabase .from('agents').select('*').eq('id',id).single();return{data,error};},async updateStatus(id,status){const{data,error}=await supabase .from('agents').update({status,updated_at: new Date().toISOString()}).eq('id',id).select().single();return{data,error};},async createTask(task){const user=await auth.getUser();const{data,error}=await supabase .from('agent_tasks').insert({...task,created_by: user?.id,status: 'pending'}).select().single();return{data,error};},async getTasks(agentId=null){let query=supabase.from('agent_tasks').select('*,agent:agents(name)');if(agentId)query=query.eq('agent_id',agentId);const{data,error}=await query.order('created_at',{ascending: false});return{data,error};}};export const analytics={async getCampaignDaily(campaignId,days=7){const endDate=new Date();const startDate=new Date();startDate.setDate(startDate.getDate()-days);const{data,error}=await supabase .from('campaign_analytics').select('*').eq('campaign_id',campaignId).gte('date',startDate.toISOString().split('T')[0]).lte('date',endDate.toISOString().split('T')[0]).order('date',{ascending: true});return{data,error};},async getAggregatedStats(days=7){const endDate=new Date();const startDate=new Date();startDate.setDate(startDate.getDate()-days);const{data,error}=await supabase .from('campaign_analytics').select('date,reach,impressions,clicks,conversions,cost').gte('date',startDate.toISOString().split('T')[0]).lte('date',endDate.toISOString().split('T')[0]).order('date',{ascending: true});if(error)return{data: null,error};const grouped={};data.forEach(row=>{if(!grouped[row.date]){grouped[row.date]={date: row.date,reach: 0,impressions: 0,clicks: 0,conversions: 0,cost: 0};}grouped[row.date].reach+=row.reach||0;grouped[row.date].impressions+=row.impressions||0;grouped[row.date].clicks+=row.clicks||0;grouped[row.date].conversions+=row.conversions||0;grouped[row.date].cost+=row.cost||0;});return{data: Object.values(grouped),error: null};}};export const approvals={async getAll(status='pending'){const{data,error}=await supabase .from('content_approvals').select('*,designer:users(full_name)').eq('status',status).order('created_at',{ascending: false});return{data,error};},async getById(id){const{data,error}=await supabase .from('content_approvals').select('*,designer:users(full_name)').eq('id',id).single();return{data,error};},async updateStatus(id,status,feedback){const{data,error}=await supabase .from('content_approvals').update({status,feedback,updated_at: new Date().toISOString()}).eq('id',id).select().single();return{data,error};}};export default{leads,clients,projects,campaigns,invoices,deals,content,budget,activities,strategic,seo,workflows,agents,analytics,approvals};